export default function StepSolver({ steps, finalAnswer }) {
  const [currentStep, setCurrentStep] = useState(0);

  if (!steps || steps.length === 0) return null;

  const step = steps[currentStep];
  const isFinished = currentStep === steps.length - 1;

  return (
    <div style={{
      border: '1px solid var(--border)',
      borderRadius: 'var(--radius-lg)',
      overflow: 'hidden',
      background: 'var(--bg-card)',
      marginTop: 16
    }}>
      {/* Progress Dots / Steps Indicator */}
      <div style={{
        padding: '12px 16px',
        background: 'var(--bg-tertiary)',
        display: 'flex',
        alignItems: 'center',
        gap: 8,
        borderBottom: '1px solid var(--border)'
      }}>
        {steps.map((_, i) => (
          <button
            key={i}
            onClick={() => setCurrentStep(i)}
            style={{
              flex: 1,
              height: 6,
              borderRadius: 3,
              background: i <= currentStep ? 'var(--accent)' : 'var(--border)',
              transition: '0.3s ease',
              border: 'none',
              cursor: 'pointer'
            }}
            title={`Langkah ${i + 1}`}
          />
        ))}
      </div>

      <div style={{ padding: '24px 20px', minHeight: 320, display: 'flex', flexDirection: 'column' }}>
        <AnimatePresence mode="wait">
          <motion.div
            key={currentStep}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.3 }}
            style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 20 }}
          >
            {/* Step Header */}
            <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
              <span style={{
                background: 'var(--accent-light)',
                color: 'var(--accent)',
                padding: '4px 10px',
                borderRadius: 'var(--radius-sm)',
                fontWeight: 700,
                fontSize: '0.85rem'
              }}>
                Langkah {currentStep + 1} / {steps.length}
              </span>
              <h4 style={{ margin: 0, fontSize: '1.05rem', fontWeight: 600 }}>
                {step.title || 'Penjelasan'}
              </h4>
            </div>

            {/* Visual (if any) */}
            {step.visual && (
              <div style={{ display: 'flex', justifyContent: 'center', margin: '10px 0' }}>
                <GeoVisual
                  type={step.visual.type}
                  data={step.visual.data}
                  width={step.visual.width || 320}
                  height={step.visual.height || 240}
                />
              </div>
            )}

            {/* Explanation Text */}
            <p style={{
              fontSize: '0.95rem',
              lineHeight: 1.7,
              color: 'var(--text-secondary)'
            }}>
              {step.text}
            </p>

            {/* Math Formula */}
            {step.math && (
              <div style={{
                padding: '16px',
                background: 'var(--bg-tertiary)',
                borderRadius: 'var(--radius-md)',
                display: 'flex',
                justifyContent: 'center'
              }}>
                <Formula tex={step.math} display />
              </div>
            )}

            {/* Final Answer Highlight */}
            {isFinished && finalAnswer && (
              <motion.div
                initial={{ scale: 0.9, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                transition={{ delay: 0.3 }}
                style={{
                  marginTop: 'auto',
                  padding: '12px 16px',
                  background: 'var(--success-light)',
                  border: '1px solid var(--success)',
                  borderRadius: 'var(--radius-md)',
                  color: 'var(--success)',
                  fontWeight: 600,
                  textAlign: 'center',
                  fontSize: '1.05rem'
                }}
              >
                Γ£à Jawaban Akhir: {finalAnswer}
              </motion.div>
            )}
          </motion.div>
        </AnimatePresence>
      </div>

      {/* Navigation Controls */}
      <div style={{
        padding: '16px 20px',
        borderTop: '1px solid var(--border)',
        display: 'flex',
        justifyContent: 'space-between',
        background: 'var(--bg-tertiary)'
      }}>
        <button
          className="btn btn-secondary"
          onClick={() => setCurrentStep(c => Math.max(0, c - 1))}
          disabled={currentStep === 0}
        >
          ΓåÉ Sebelumnya
        </button>
        <button
          className={isFinished ? 'btn btn-success' : 'btn btn-primary'}
          onClick={() => {
            if (!isFinished) setCurrentStep(c => c + 1);
          }}
          disabled={isFinished}
        >
          {isFinished ? 'Selesai Γ£¿' : 'Selanjutnya ΓåÆ'}
        </button>
      </div>
    </div>
  );
}

import { createContext, useContext, useState, useEffect } from 'react';

const AppContext = createContext();

const defaultState = {
  darkMode: false,
  xp: 0,
  level: 1,
  completedTopics: [],
  latihanHistory: [],
  ujianHistory: [],
  bookmarks: [],
  markedDifficult: [],
  wrongAnswers: [],
  topicProgress: {},
};

function loadState() {
  try {
    const saved = localStorage.getItem('mathlearn_state');
    return saved ? { ...defaultState, ...JSON.parse(saved) } : defaultState;
  } catch {
    return defaultState;
  }
}

export function AppProvider({ children }) {
  const [state, setState] = useState(loadState);

  useEffect(() => {
    localStorage.setItem('mathlearn_state', JSON.stringify(state));
  }, [state]);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', state.darkMode ? 'dark' : 'light');
  }, [state.darkMode]);

  const toggleDarkMode = () => setState(s => ({ ...s, darkMode: !s.darkMode }));

  const addXP = (amount) => {
    setState(s => {
      const newXP = s.xp + amount;
      const newLevel = Math.floor(newXP / 100) + 1;
      return { ...s, xp: newXP, level: newLevel };
    });
  };

  const addLatihanResult = (result) => {
    setState(s => ({
      ...s,
      latihanHistory: [...s.latihanHistory, { ...result, date: new Date().toISOString() }],
    }));
  };

  const addUjianResult = (result) => {
    setState(s => ({
      ...s,
      ujianHistory: [...s.ujianHistory, { ...result, date: new Date().toISOString() }],
    }));
  };

  const toggleBookmark = (questionId) => {
    setState(s => ({
      ...s,
      bookmarks: s.bookmarks.includes(questionId)
        ? s.bookmarks.filter(id => id !== questionId)
        : [...s.bookmarks, questionId],
    }));
  };

  const toggleDifficult = (questionId) => {
    setState(s => ({
      ...s,
      markedDifficult: s.markedDifficult.includes(questionId)
        ? s.markedDifficult.filter(id => id !== questionId)
        : [...s.markedDifficult, questionId],
    }));
  };

  const addWrongAnswer = (questionId) => {
    setState(s => ({
      ...s,
      wrongAnswers: s.wrongAnswers.includes(questionId)
        ? s.wrongAnswers
        : [...s.wrongAnswers, questionId],
    }));
  };

  const removeWrongAnswer = (questionId) => {
    setState(s => ({
      ...s,
      wrongAnswers: s.wrongAnswers.filter(id => id !== questionId),
    }));
  };

  const updateTopicProgress = (topicId, correct, total) => {
    setState(s => ({
      ...s,
      topicProgress: {
        ...s.topicProgress,
        [topicId]: {
          correct: (s.topicProgress[topicId]?.correct || 0) + correct,
          total: (s.topicProgress[topicId]?.total || 0) + total,
        },
      },
    }));
  };

  const markTopicCompleted = (topicId) => {
    setState(s => ({
      ...s,
      completedTopics: s.completedTopics.includes(topicId)
        ? s.completedTopics
        : [...s.completedTopics, topicId],
    }));
  };

  const resetProgress = () => setState(defaultState);

  const value = {
    ...state,
    toggleDarkMode,
    addXP,
    addLatihanResult,
    addUjianResult,
    toggleBookmark,
    toggleDifficult,
    addWrongAnswer,
    removeWrongAnswer,
    updateTopicProgress,
    markTopicCompleted,
    resetProgress,
  };

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
}

export function useApp() {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error('useApp must be used within AppProvider');
  return ctx;
}

