              <h3 style={{ fontSize: '1rem', fontWeight: 700, marginBottom: 8 }}>Γ¥î Soal Salah</h3>
              <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: 12 }}>
                {wrongAnswers.length} soal perlu direview
              </p>
              <Link to="/latihan" className="btn btn-danger btn-sm">
                Review Soal Salah
              </Link>
            </div>
          )}

          {/* Activity */}
          {recentActivity.length > 0 && !wrongAnswers.length && (
            <div className="card">
              <h3 style={{ fontSize: '1rem', fontWeight: 700, marginBottom: 12 }}>≡ƒòÉ Aktivitas Terakhir</h3>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                {recentActivity.map((act, i) => (
                  <div key={i} style={{
                    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                    padding: '8px 0', borderBottom: i < recentActivity.length - 1 ? '1px solid var(--border-light)' : 'none',
                    fontSize: '0.85rem'
                  }}>
                    <span style={{ color: 'var(--text-secondary)' }}>
                      {act.type === 'ujian' ? '≡ƒô¥ Simulasi' : `Γ£Å∩╕Å ${act.topik || 'Latihan'}`}
                    </span>
                    <span className={`badge ${act.score >= 70 ? 'badge-green' : 'badge-yellow'}`}>
                      {act.score}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </motion.div>
      </div>
    </motion.div>
  );
}

