import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import QuestionVisual from '../components/QuestionVisual';

export default function HasilUjian() {
  const [result, setResult] = useState(null);
  const [showPembahasan, setShowPembahasan] = useState({});

  useEffect(() => {
    const data = sessionStorage.getItem('exam_result');
    if (data) {
      setResult(JSON.parse(data));
    }
  }, []);

  if (!result) {
    return (
      <div className="empty-state">
        <div className="empty-icon">≡ƒô¥</div>
        <h3>Belum ada hasil ujian</h3>
        <p>Mulai simulasi ujian terlebih dahulu</p>
        <Link to="/simulasi" className="btn btn-primary mt-4">Mulai Simulasi</Link>
      </div>
    );
  }

  const { score, correct, total, timeUsed, details } = result;
  const labels = ['A', 'B', 'C', 'D'];
  const formatTime = (s) => `${Math.floor(s / 60)} menit ${s % 60} detik`;

  // Topic analysis
  const topicStats = {};
  details.forEach(d => {
    const topic = d.question.topik;
    if (!topicStats[topic]) topicStats[topic] = { correct: 0, total: 0 };
    topicStats[topic].total++;
    if (d.isCorrect) topicStats[topic].correct++;
  });

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
      {/* Score Header */}
      <div className="card" style={{ textAlign: 'center', padding: 40, marginBottom: 24 }}>
        <div style={{ fontSize: '4rem', marginBottom: 12 }}>
          {score >= 80 ? '≡ƒÄë' : score >= 60 ? '≡ƒæì' : '≡ƒÆ¬'}
        </div>
        <h1 style={{ fontSize: '1.5rem', fontWeight: 800, marginBottom: 8 }}>Hasil Simulasi Ujian</h1>
        <div style={{
          fontSize: '4rem', fontWeight: 900, lineHeight: 1,
          color: score >= 70 ? 'var(--success)' : score >= 50 ? 'var(--warning)' : 'var(--danger)',
          marginBottom: 12,
        }}>
          {score}
        </div>
        <p style={{ color: 'var(--text-secondary)', fontSize: '1.1rem', marginBottom: 4 }}>
          {correct} / {total} benar
        </p>
        <p style={{ color: 'var(--text-tertiary)', fontSize: '0.9rem' }}>
          ΓÅ▒∩╕Å Waktu: {formatTime(timeUsed)}
        </p>
      </div>

      {/* Stats Grid */}
      <div className="grid-3" style={{ marginBottom: 24 }}>
        <div className="card stat-card">
          <div className="stat-value" style={{ color: 'var(--success)' }}>{correct}</div>
          <div className="stat-label">Γ£à Benar</div>
        </div>
        <div className="card stat-card">
          <div className="stat-value" style={{ color: 'var(--danger)' }}>{total - correct}</div>
          <div className="stat-label">Γ¥î Salah</div>
        </div>
        <div className="card stat-card">
          <div className="stat-value" style={{ color: 'var(--accent)' }}>
            {details.filter(d => d.userAnswer === undefined).length}
          </div>
          <div className="stat-label">ΓÅ¡∩╕Å Tidak dijawab</div>
        </div>
      </div>

      {/* Topic Analysis */}
      <div className="card" style={{ marginBottom: 24 }}>
        <h2 style={{ fontSize: '1.1rem', fontWeight: 700, marginBottom: 16 }}>≡ƒôè Analisis per Topik</h2>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
          {Object.entries(topicStats).map(([topic, stats]) => {
            const pct = Math.round((stats.correct / stats.total) * 100);
            return (
              <div key={topic} style={{
                display: 'flex', alignItems: 'center', gap: 12,
                padding: '10px 14px', background: 'var(--bg-tertiary)',
                borderRadius: 'var(--radius-sm)',
              }}>
                <span style={{ flex: 1, fontWeight: 500, fontSize: '0.9rem', textTransform: 'capitalize' }}>
                  {topic.replace('-', ' ')}
                </span>
                <span style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                  {stats.correct}/{stats.total}
                </span>
                <div className="progress-bar" style={{ width: 80, height: 6 }}>
                  <div className="progress-fill" style={{
                    width: `${pct}%`,
                    background: pct >= 70 ? 'var(--success)' : pct >= 50 ? 'var(--warning)' : 'var(--danger)',
                  }} />
                </div>
                <span className={`badge ${pct >= 70 ? 'badge-green' : pct >= 50 ? 'badge-yellow' : 'badge-red'}`}>
                  {pct}%
                </span>
              </div>
            );
          })}
        </div>
      </div>

      {/* Detailed Review */}
      <div className="card" style={{ marginBottom: 24 }}>
        <h2 style={{ fontSize: '1.1rem', fontWeight: 700, marginBottom: 16 }}>≡ƒô¥ Pembahasan Lengkap</h2>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          {details.map((d, i) => {
            const q = d.question;
            const expanded = showPembahasan[i];

            return (
              <div key={i} style={{
                border: '1px solid var(--border)', borderRadius: 'var(--radius-md)',
                borderLeft: `4px solid ${d.isCorrect ? 'var(--success)' : d.userAnswer === undefined ? 'var(--text-tertiary)' : 'var(--danger)'}`,
                overflow: 'hidden',
              }}>
                <button
                  onClick={() => setShowPembahasan(p => ({ ...p, [i]: !p[i] }))}
                  style={{
                    width: '100%', padding: '12px 16px', display: 'flex',
                    justifyContent: 'space-between', alignItems: 'center',
                    background: 'transparent', textAlign: 'left', color: 'var(--text-primary)',
                    border: 'none', cursor: 'pointer', fontSize: '0.9rem',
                  }}
                >
                  <span style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <span>{d.isCorrect ? 'Γ£à' : d.userAnswer === undefined ? 'ΓÅ¡∩╕Å' : 'Γ¥î'}</span>
                    <span style={{ fontWeight: 600 }}>Soal {i + 1}</span>
                    <span className={`badge ${q.tingkat === 'mudah' ? 'badge-green' : q.tingkat === 'sedang' ? 'badge-yellow' : 'badge-red'}`} style={{ fontSize: '0.7rem' }}>
                      {q.tingkat}
                    </span>
                  </span>
                  <span style={{
                    transform: expanded ? 'rotate(180deg)' : 'rotate(0deg)',
                    transition: '0.2s',
                  }}>Γû╝</span>
                </button>

                {expanded && (
                  <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    style={{ padding: '0 16px 16px' }}
                  >
                    <p style={{ fontSize: '0.9rem', lineHeight: 1.6, marginBottom: 12 }}>
                      {q.pertanyaan}
                    </p>
                    <QuestionVisual question={q} />
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 6, marginBottom: 12 }}>
                      {q.opsi.map((opsi, oi) => {
                        let style = {
                          padding: '8px 12px', borderRadius: 'var(--radius-sm)',
                          fontSize: '0.85rem', display: 'flex', gap: 8,
                          border: '1px solid var(--border)',
                        };
                        if (oi === q.jawaban) {
                          style.background = 'var(--success-light)';
                          style.borderColor = 'var(--success)';
                        } else if (oi === d.userAnswer && oi !== q.jawaban) {
                          style.background = 'var(--danger-light)';
                          style.borderColor = 'var(--danger)';
                        }
                        return (
                          <div key={oi} style={style}>
                            <strong>{labels[oi]}.</strong>
                            <span>{opsi}</span>
                            {oi === q.jawaban && <span>Γ£à</span>}
                            {oi === d.userAnswer && oi !== q.jawaban && <span>Γ¥î</span>}
                          </div>
                        );
                      })}
                    </div>
                    {d.userAnswer === undefined && (
                      <p style={{ color: 'var(--text-tertiary)', fontSize: '0.85rem', marginBottom: 8 }}>
                        ΓÅ¡∩╕Å Tidak dijawab
                      </p>
                    )}
                    <div className="pembahasan-box">
                      <h4>≡ƒÆí Pembahasan</h4>
                      <pre>{q.pembahasan}</pre>
                    </div>
                  </motion.div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Actions */}
      <div style={{ display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' }}>
        <Link to="/simulasi" className="btn btn-primary btn-lg">≡ƒöä Ulang Simulasi</Link>
        <Link to="/progress" className="btn btn-secondary btn-lg">≡ƒôè Lihat Progress</Link>
        <Link to="/" className="btn btn-secondary btn-lg">≡ƒÅá Dashboard</Link>
      </div>
    </motion.div>
  );
}

import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { useApp } from '../context/AppContext';
import materiData from '../data/materi.json';

export default function Latihan() {
  const { topicProgress } = useApp();

  return (
    <div>
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontSize: '1.5rem', fontWeight: 800, marginBottom: 4 }}>Γ£Å∩╕Å Latihan Soal</h1>
        <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>
          Pilih topik untuk berlatih ΓÇö mode timer atau santai
        </p>
      </div>

      <div className="grid-2">
        {materiData.map((topik, i) => {
          const prog = topicProgress[topik.id];
          const pct = prog && prog.total > 0 ? Math.round((prog.correct / prog.total) * 100) : 0;

          return (
            <motion.div
              key={topik.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.06 }}
            >
              <Link to={`/latihan/${topik.id}`} style={{ color: 'inherit', display: 'block' }}>
                <div className="card card-clickable">
                  <div style={{ display: 'flex', alignItems: 'center', gap: 14, marginBottom: 12 }}>
                    <div style={{
                      width: 48, height: 48, borderRadius: 'var(--radius-md)',
                      background: 'var(--accent-subtle)', display: 'flex',
                      alignItems: 'center', justifyContent: 'center', fontSize: '1.4rem',
                    }}>
                      {topik.icon}
                    </div>
                    <div>
                      <h3 style={{ fontSize: '1rem', fontWeight: 600 }}>{topik.title}</h3>
                      <span style={{ fontSize: '0.82rem', color: 'var(--text-tertiary)' }}>
                        Tier {topik.tier}
                      </span>
                    </div>
                  </div>
                  {prog && prog.total > 0 ? (
                    <>
                      <div className="progress-bar" style={{ marginBottom: 6, height: 5 }}>
                        <div className="progress-fill" style={{ width: `${pct}%` }} />
                      </div>
                      <div style={{ fontSize: '0.8rem', color: 'var(--text-tertiary)' }}>
                        {prog.correct}/{prog.total} benar ({pct}%)
                      </div>
                    </>
                  ) : (
                    <div style={{ fontSize: '0.82rem', color: 'var(--text-tertiary)' }}>
                      Belum ada latihan
                    </div>
                  )}
                </div>
              </Link>
            </motion.div>
          );
        })}
      </div>

      <div style={{ marginTop: 24, textAlign: 'center' }}>
        <Link to="/simulasi" className="btn btn-primary btn-lg">
          ≡ƒô¥ Atau langsung Simulasi Ujian ΓåÆ
        </Link>
      </div>
    </div>
  );
}

import { useParams, Link } from 'react-router-dom';
import { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useApp } from '../context/AppContext';
import soalData from '../data/soal.json';
import QuestionVisual from '../components/QuestionVisual';
import materiData from '../data/materi.json';

export default function LatihanSoal() {
  const { topikId } = useParams();
  const { addXP, addLatihanResult, updateTopicProgress, toggleBookmark, toggleDifficult, bookmarks, markedDifficult, addWrongAnswer, removeWrongAnswer } = useApp();

  const topik = materiData.find(t => t.id === topikId);
  const allQuestions = soalData.latihan.filter(q => q.topik === topikId);

  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState(null);
  const [showResult, setShowResult] = useState(false);
  const [score, setScore] = useState({ correct: 0, total: 0 });
  const [useTimer, setUseTimer] = useState(false);
  const [timer, setTimer] = useState(0);
  const [started, setStarted] = useState(false);
  const [finished, setFinished] = useState(false);
  const intervalRef = useRef(null);

  const questions = allQuestions;
  const current = questions[currentIndex];

  useEffect(() => {
    if (useTimer && started && !finished) {
      intervalRef.current = setInterval(() => setTimer(t => t + 1), 1000);
      return () => clearInterval(intervalRef.current);
    }
  }, [useTimer, started, finished]);

  const checkAnswer = () => {
    if (selectedAnswer === null) return;
    setShowResult(true);
    const isCorrect = selectedAnswer === current.jawaban;
    setScore(s => ({
      correct: s.correct + (isCorrect ? 1 : 0),
      total: s.total + 1,
    }));
    if (isCorrect) {
      addXP(10);
      removeWrongAnswer(current.id);
    } else {
      addWrongAnswer(current.id);
    }
  };

  const nextQuestion = () => {
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(i => i + 1);
      setSelectedAnswer(null);
      setShowResult(false);
    } else {
      // Finished
      setFinished(true);
      clearInterval(intervalRef.current);
      updateTopicProgress(topikId, score.correct + (selectedAnswer === current?.jawaban ? 1 : 0), score.total + 1);
      addLatihanResult({
        type: 'latihan',
        topik: topik?.title || topikId,
        topikId,
        score: Math.round(((score.correct) / questions.length) * 100),
        correct: score.correct,
        total: questions.length,
        time: timer,
      });
    }
  };

  const restart = () => {
    setCurrentIndex(0);
    setSelectedAnswer(null);
    setShowResult(false);
    setScore({ correct: 0, total: 0 });
    setTimer(0);
    setFinished(false);
    setStarted(true);
  };

  const formatTime = (s) => {
    const m = Math.floor(s / 60);
    const sec = s % 60;
    return `${String(m).padStart(2, '0')}:${String(sec).padStart(2, '0')}`;
  };

  if (!topik || questions.length === 0) {
    return (
      <div className="empty-state">
        <div className="empty-icon">≡ƒôÜ</div>
        <h3>Belum ada soal untuk topik ini</h3>
        <Link to="/latihan" className="btn btn-primary mt-4">Kembali</Link>
      </div>
    );
  }

  if (!started) {
    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} style={{ maxWidth: 600, margin: '0 auto' }}>
        <div className="card" style={{ textAlign: 'center', padding: 40 }}>
          <div style={{ fontSize: '3rem', marginBottom: 16 }}>{topik.icon}</div>
          <h2 style={{ fontSize: '1.4rem', fontWeight: 700, marginBottom: 8 }}>
            Latihan: {topik.title}
          </h2>
          <p style={{ color: 'var(--text-secondary)', marginBottom: 24 }}>
            {questions.length} soal tersedia
          </p>

          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 24 }}>
            <label style={{
              display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px',
              background: 'var(--bg-tertiary)', borderRadius: 'var(--radius-sm)', cursor: 'pointer',
              border: !useTimer ? '2px solid var(--accent)' : '2px solid transparent',
            }}>
              <input type="radio" checked={!useTimer} onChange={() => setUseTimer(false)} />
              <span><strong>≡ƒÿî Mode Santai</strong> ΓÇö Tanpa timer</span>
            </label>
            <label style={{
              display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px',
              background: 'var(--bg-tertiary)', borderRadius: 'var(--radius-sm)', cursor: 'pointer',
              border: useTimer ? '2px solid var(--accent)' : '2px solid transparent',
            }}>
              <input type="radio" checked={useTimer} onChange={() => setUseTimer(true)} />
              <span><strong>ΓÅ▒∩╕Å Mode Timer</strong> ΓÇö Hitung waktu</span>
            </label>
          </div>

          <button className="btn btn-primary btn-lg btn-full" onClick={() => setStarted(true)}>
            ≡ƒÜÇ Mulai Latihan
          </button>
        </div>
      </motion.div>
    );
  }

  if (finished) {
    const pct = Math.round((score.correct / questions.length) * 100);
    return (
      <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} style={{ maxWidth: 500, margin: '0 auto' }}>
        <div className="card" style={{ textAlign: 'center', padding: 40 }}>
          <div style={{ fontSize: '4rem', marginBottom: 16 }}>
            {pct >= 80 ? '≡ƒÄë' : pct >= 60 ? '≡ƒæì' : '≡ƒÆ¬'}
          </div>
          <h2 style={{ fontSize: '1.5rem', fontWeight: 800, marginBottom: 8 }}>
            Latihan Selesai!
          </h2>
          <div style={{ fontSize: '2.5rem', fontWeight: 800, color: pct >= 70 ? 'var(--success)' : 'var(--warning)', marginBottom: 12 }}>
            {pct}
          </div>
          <p style={{ color: 'var(--text-secondary)', marginBottom: 8 }}>
            {score.correct} / {questions.length} benar
          </p>
          {useTimer && (
            <p style={{ color: 'var(--text-tertiary)', fontSize: '0.9rem', marginBottom: 20 }}>
              ΓÅ▒∩╕Å Waktu: {formatTime(timer)}
            </p>
          )}
          <p style={{ color: 'var(--success)', fontSize: '0.9rem', marginBottom: 24 }}>
            +{score.correct * 10} XP earned!
          </p>
          <div style={{ display: 'flex', gap: 10, justifyContent: 'center', flexWrap: 'wrap' }}>
            <button className="btn btn-primary" onClick={restart}>≡ƒöä Ulangi</button>
            <Link to="/latihan" className="btn btn-secondary">≡ƒôÜ Topik Lain</Link>
          </div>
        </div>
      </motion.div>
    );
  }

  const isBookmarked = bookmarks.includes(current.id);
  const isDifficult = markedDifficult.includes(current.id);
  const labels = ['A', 'B', 'C', 'D'];

  return (
    <div style={{ maxWidth: 700, margin: '0 auto' }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
        <div>
          <Link to="/latihan" style={{ color: 'var(--text-tertiary)', fontSize: '0.85rem' }}>
            ΓåÉ Kembali
          </Link>
          <h2 style={{ fontSize: '1.1rem', fontWeight: 700, marginTop: 4 }}>
            {topik.icon} {topik.title}
          </h2>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          {useTimer && (
            <div className="timer-display" style={{ fontSize: '1.1rem' }}>
              ΓÅ▒∩╕Å {formatTime(timer)}
            </div>
          )}
          <span className="badge badge-blue">{currentIndex + 1} / {questions.length}</span>
        </div>
      </div>

      {/* Progress */}
      <div className="progress-bar" style={{ marginBottom: 20, height: 4 }}>
        <div className="progress-fill" style={{ width: `${((currentIndex + 1) / questions.length) * 100}%` }} />
      </div>

      {/* Question Card */}
      <AnimatePresence mode="wait">
        <motion.div
          key={currentIndex}
          initial={{ opacity: 0, x: 40 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: -40 }}
          transition={{ duration: 0.2 }}
        >
          <div className="card">
            {/* Badges */}
            <div style={{ display: 'flex', gap: 8, marginBottom: 12, flexWrap: 'wrap' }}>
              <span className={`badge ${current.tingkat === 'mudah' ? 'badge-green' : current.tingkat === 'sedang' ? 'badge-yellow' : 'badge-red'}`}>
                {current.tingkat === 'mudah' ? '≡ƒƒó' : current.tingkat === 'sedang' ? '≡ƒƒí' : '≡ƒö┤'} {current.tingkat}
              </span>
              <button
                className={`badge ${isBookmarked ? 'badge-yellow' : ''}`}
                style={{ cursor: 'pointer', border: '1px solid var(--border)' }}
                onClick={() => toggleBookmark(current.id)}
              >
                {isBookmarked ? '≡ƒöû Bookmarked' : '≡ƒöû Bookmark'}
              </button>
              <button
                className={`badge ${isDifficult ? 'badge-red' : ''}`}
                style={{ cursor: 'pointer', border: '1px solid var(--border)' }}
                onClick={() => toggleDifficult(current.id)}
              >
                {isDifficult ? 'ΓÜí Sulit!' : 'ΓÜí Tandai Sulit'}
              </button>
            </div>

            <div className="question-text">{current.pertanyaan}</div>

            <QuestionVisual question={current} />

            <div className="option-list">
              {current.opsi.map((opsi, i) => {
                let className = 'option-btn';
                if (showResult) {
                  if (i === current.jawaban) className += ' correct';
                  else if (i === selectedAnswer && i !== current.jawaban) className += ' wrong';
                } else if (i === selectedAnswer) {
                  className += ' selected';
                }

                return (
                  <button
                    key={i}
                    className={className}
                    onClick={() => !showResult && setSelectedAnswer(i)}
                    disabled={showResult}
                  >
                    <span className="option-label">{labels[i]}</span>
                    <span>{opsi}</span>
                  </button>
                );
              })}
            </div>

            {/* Pembahasan */}
            {showResult && (
              <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                className="pembahasan-box"
              >
                <h4>≡ƒÆí Pembahasan</h4>
                <pre>{current.pembahasan}</pre>
              </motion.div>
            )}

            {/* Actions */}
            <div style={{ marginTop: 20, display: 'flex', gap: 10 }}>
              {!showResult ? (
                <button
                  className="btn btn-primary btn-full"
                  onClick={checkAnswer}
                  disabled={selectedAnswer === null}
                >
                  Γ£à Cek Jawaban
                </button>
              ) : (
                <button className="btn btn-primary btn-full" onClick={nextQuestion}>
                  {currentIndex < questions.length - 1 ? 'Γ₧í∩╕Å Soal Berikutnya' : '≡ƒÅü Selesai'}
                </button>
              )}
            </div>
          </div>
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

